bind.getValue:
function(elem) {
  var cardInner = elem.querySelector('.ib-card-inner');
  return cardInner && cardInner.style.height !== '';
}

bind.setValue:
function(elem, v, vm, util) {
  var fh = vm['forceHeight'] || vm['flip'];
  var cih = '';
  var cfh = '';
  var ibCardFront = elem.querySelector('.ib-card-front');
  var ibCardInner = elem.querySelector('.ib-card-inner');
  var ibCardBody = elem.querySelector('.ib-card-front .card-body');
  if (fh) {
    cih = v + 'px';
    cfh = 'calc(' + v + 'px - 100px)';
    util.setStyleMCE(ibCardFront, 'position', '');
  } else {
    util.setStyleMCE(ibCardFront, 'position', 'relative');
  }
  util.setStyleMCE(ibCardInner, 'height', cih);
  util.setStyleMCE(ibCardBody, 'height', cfh);
}

function(elem, v) {
  if (v) {
    if (elem.querySelector('.ib-card-front img.card-img-top')) {
      return;
    }
    var img = '<img src="https://picsum.photos/300/100" class="card-img-top" alt="Imatge targeta">';
    elem.querySelector('.ib-card-front')?.insertAdjacentHTML('afterbegin', img);
  } else {
    var imgEl = elem.querySelector('.ib-card-front img.card-img-top');
    if (imgEl) { imgEl.remove(); }
  }
}

function(elem, v) {
  if (v) {
    if(elem.querySelector('.ib-card-front div.card-header')) {
      return;
    }
    var imgtop = elem.querySelector('.ib-card-front img.card-img-top');
    var header = '<div class="card-header">Capçalera de targeta</div>';
    if (imgtop) {
      imgtop.insertAdjacentHTML('afterend', header);
    } else {
      elem.querySelector('.ib-card-front')?.insertAdjacentHTML('afterbegin', header);
    }
  } else {
    var cardHeader = elem.querySelector('.ib-card-front div.card-header');
    if (cardHeader) { cardHeader.remove(); }
  }
}

function(elem, v) {
  if (v) {
    if (elem.querySelector('.ib-card-front div.card-footer')) {
      return;
    }
    elem.querySelector('.ib-card-front')?.insertAdjacentHTML('beforeend', '<div class="card-footer">Peu de targeta</div>');
  } else {
    var cardFooter = elem.querySelector('.ib-card-front div.card-footer');
    if (cardFooter) { cardFooter.remove(); }
  }
}

function(elem, v) {
  if(v) {
    if (elem.classList.contains('ib-card-flip')) {
      return;
    }
    elem.classList.add('ib-card-flip');
    const html = '<div class="card ib-card-back" data-face="back"><div class="card-body"><h5 class="card-title">Títol revers targeta</h5><p class="card-text">Text del revers de la targeta.</p></div></div>';
    elem.querySelector('.ib-card-front')?.insertAdjacentHTML('afterend', html);
  } else {
    elem.classList.remove('ib-card-flip');
    var cardBack = elem.querySelector('.ib-card-back');
    if (cardBack) { cardBack.remove(); }
  }
}
